+
+	t.Run("add_json_output", func(t *testing.T) {
+		j1 := bdCreate(t, bd, dir, "JSON dep A", "--type", "task")
+		j2 := bdCreate(t, bd, dir, "JSON dep B", "--type", "task")
+		m := bdDepJSON(t, bd, dir, "add", j1.ID, j2.ID)
