+		if !strings.Contains(out, "Removed") {
+			t.Errorf("expected 'Removed' in output: %s", out)
+		}
+	})
+
+	t.Run("remove_rm_alias", func(t *testing.T) {
+		r1 := bdCreate(t, bd, dir, "Rm A", "--type", "task")
+		r2 := bdCreate(t, bd, dir, "Rm B", "--type", "task")
