+	bd := buildEmbeddedBD(t)
+	dir, _, _ := bdInit(t, bd, "--prefix", "grc")
+
+	// Create issues with deps.
+	var ids []string
+	for i := 0; i < 8; i++ {
+		issue := bdCreate(t, bd, dir, fmt.Sprintf("concurrent-graph-%d", i), "--type", "task")
+		ids = append(ids, issue.ID)
+	}
+	for i := 0; i < 4; i++ {
+		bdDep(t, bd, dir, "add", ids[i*2], ids[i*2+1])
+	}
+
+	const numWorkers = 8
+	type workerResult struct {
+		worker int
+		err    error
+	}
+	results := make([]workerResult, numWorkers)
+	var wg sync.WaitGroup
+	wg.Add(numWorkers)
+
+	for w := 0; w < numWorkers; w++ {
+		go func(worker int) {
+			defer wg.Done()
+			r := workerResult{worker: worker}
+
+			formats := [][]string{
+				{ids[worker]},
+				{"--compact", ids[worker]},
+				{"--dot", ids[worker]},
+				{"--box", ids[worker]},
+				{"--all"},
+				{"--all", "--compact"},
+				{"--all", "--dot"},
+				{ids[worker]},
+			}
+			f := formats[worker%len(formats)]
+
+			args := append([]string{"graph"}, f...)
+			cmd := exec.Command(bd, args...)
+			cmd.Dir = dir
+			cmd.Env = bdEnv(dir)
+			out, err := cmd.CombinedOutput()
+			if err != nil {
+				r.err = fmt.Errorf("worker %d graph: %v\n%s", worker, err, out)
+			}
+			results[worker] = r
+		}(w)
+	}
+	wg.Wait()
+
+	for _, r := range results {
+		if r.err != nil {
+			t.Errorf("worker %d failed: %v", r.worker, r.err)
+		}
+	}
+}

